class Solution:
    def findPairs(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        count = Counter(nums)
        pairs = 0

        for num in count:
            # Case 1: k == 0, need at least 2 of same number
            if k == 0:
                if count[num] > 1:
                    pairs += 1
            # Case 2: k > 0, check if complement exists
            elif k > 0 and num + k in count:
                pairs += 1

        return pairs
